input.command:
cat > /tmp/test_multiline.txt <<'EOF'
IMPORTANT: This is line one.

This is line two after a blank line.
This is line three.
EOF

# Test how it gets substituted and output through jq
test_content=$(cat /tmp/test_multiline.txt | sed 's/line/test/g')
echo "$test_content" | jq -n --arg context "$(cat -)" '{
  "hookSpecificOutput": {
    "hookEventName": "UserPromptSubmit",
    "additionalContext": $context
  }
}'

